// admin/src/services/statsService.js
import axios from 'axios';

// Đường dẫn trỏ thẳng sang Server Admin cổng 5001
const API_BASE_URL = 'http://localhost:5001'; 

class StatsService {
    /**
     * Lấy toàn bộ dữ liệu thống kê tổng quan cho Dashboard Admin
     * @returns {Promise<Object>} Trả về cụm stats gồm người dùng, doanh thu, sản phẩm...
     */
    async getDashboardStats() {
        const token = localStorage.getItem("token");
        
        const response = await axios.get(`${API_BASE_URL}/api/stats/stats`, {
            headers: {
                "Content-Type": "application/json",
                // 🔑 Tự động đính kèm Token Bearer cho Middleware verifyAdmin phía Backend xác thực
                "Authorization": `Bearer ${token}`
            }
        });
        
        return response.data; // Trả thẳng cục bộ dữ liệu stats về cho Component sử dụng
    }
}

export default new StatsService();
